class Solution:
    def numDecodings(self, s: str) -> int:
        MOD=10**9+7
        n=len(s); dp=[0]*(n+1); dp[0]=1; dp[1]=9 if s[0]=='*' else (0 if s[0]=='0' else 1)
        for i in range(2,n+1):
            if s[i-1]=='*': dp[i]=9*dp[i-1]
            elif s[i-1]!='0': dp[i]=dp[i-1]
            a=s[i-2]
            if a=='*': dp[i]+=dp[i-2]*9 if s[i-1]=='*' else (dp[i-2] if s[i-1]<='6' else 0)
            elif a=='1': dp[i]+=dp[i-2]*(9 if s[i-1]=='*' else 1)
            elif a=='2': dp[i]+=dp[i-2]*(6 if s[i-1]=='*' else (1 if s[i-1]<='6' else 0))
        return dp[n]%MOD

