class Solution {
public:
    int numDecodings(string s) {
        const int MOD=1e9+7; int n=s.size();
        vector<long> dp(n+1); dp[0]=1;
        dp[1]= s[0]=='*'?9:(s[0]=='0'?0:1);
        for(int i=2;i<=n;i++){
            if(s[i-1]=='*') dp[i]=9*dp[i-1]%MOD;
            else if(s[i-1]!='0') dp[i]=dp[i-1];
            char a=s[i-2];
            if(a=='*'){ if(s[i-1]=='*') dp[i]=(dp[i]+9LL*dp[i-2])%MOD; else if(s[i-1]<='6') dp[i]=(dp[i]+dp[i-2])%MOD; }
            else if(a=='1') dp[i]=(dp[i]+(s[i-1]=='*'?9LL:1LL)*dp[i-2])%MOD;
            else if(a=='2'){ long add=s[i-1]=='*'?6:(s[i-1]<='6'); dp[i]=(dp[i]+add*dp[i-2])%MOD; }
        }
        return dp[n];
    }
};

