int numDecodings639(char* s) {
    const int MOD=1000000007;
    int n=strlen(s); if(!n||s[0]=='0') return 0;
    long dp0=1, dp1=1;
    for(int i=1;i<n;i++){
        long nd=0;
        if(s[i]!='0') nd=(nd+dp1)%MOD;
        int two=(s[i-1]-'0')*10+(s[i]-'0');
        if(two>=10&&two<=26) nd=(nd+dp0)%MOD;
        dp0=dp1; dp1=nd;
    }
    return (int)dp1;
}
